#include "funfacts.h"
#include "app.h"
typedef struct FunfactText { const char *de; const char *en; const char *pl; } FunfactText;
static const FunfactText facts[] = {
{"Funfact: Die ISS umrundet die Erde in etwa 90 Minuten.","Funfact: The ISS circles Earth in about 90 minutes.","Ciekawostka: ISS okraza Ziemie w okolo 90 minut."},
{"Funfact: Astronauten auf der ISS sehen pro Tag rund 16 Sonnenaufgaenge.","Funfact: Astronauts on the ISS see about 16 sunrises per day.","Ciekawostka: Astronauci na ISS widza okolo 16 wschodow Slonca dziennie."},
{"Funfact: Die ISS fliegt mit etwa 27600 km/h um die Erde.","Funfact: The ISS travels around Earth at about 27600 km/h.","Ciekawostka: ISS leci wokol Ziemi z predkoscia okolo 27600 km/h."},
{"Funfact: In Schwerelosigkeit trennen sich Gas und Fluessigkeit im Magen schlechter.","Funfact: In weightlessness gas and liquid separate less well in the stomach.","Ciekawostka: W niewazkosci gaz i plyn gorzej oddzielaja sie w zoladku."},
{"Funfact: Raumanzuege sind kleine Raumfahrzeuge mit eigener Lebenserhaltung.","Funfact: Spacesuits are small spacecraft with their own life support.","Ciekawostka: Skafandry kosmiczne to male statki z wlasnym podtrzymaniem zycia."},
{"Funfact: Der erste Mensch im All war Juri Gagarin im Jahr 1961.","Funfact: The first human in space was Yuri Gagarin in 1961.","Ciekawostka: Pierwszym czlowiekiem w kosmosie byl Jurij Gagarin w 1961 roku."},
{"Funfact: Der erste Mensch auf dem Mond war Neil Armstrong im Jahr 1969.","Funfact: The first human on the Moon was Neil Armstrong in 1969.","Ciekawostka: Pierwszym czlowiekiem na Ksiezycu byl Neil Armstrong w 1969 roku."},
{"Funfact: Die erste Frau im All war Walentina Tereschkowa im Jahr 1963.","Funfact: The first woman in space was Valentina Tereshkova in 1963.","Ciekawostka: Pierwsza kobieta w kosmosie byla Walentina Tierieszkowa w 1963 roku."},
{"Funfact: Apollo 11 brauchte bis zum Mond etwa vier Tage.","Funfact: Apollo 11 took about four days to reach the Moon.","Ciekawostka: Apollo 11 lecialo na Ksiezyc okolo czterech dni."},
{"Funfact: Mondstaub ist sehr fein und haftet stark an Raumanzuegen.","Funfact: Moon dust is very fine and sticks strongly to spacesuits.","Ciekawostka: Pyl ksiezycowy jest bardzo drobny i mocno przywiera do skafandrow."},
{"Funfact: Die ISS ist groesser als ein Fussballfeld, inklusive Solarmodule.","Funfact: The ISS is larger than a football field including its solar arrays.","Ciekawostka: ISS jest wieksza niz boisko pilkarskie razem z panelami slonecznymi."},
{"Funfact: Auf der ISS gibt es keine Dusche wie auf der Erde.","Funfact: There is no Earth-style shower on the ISS.","Ciekawostka: Na ISS nie ma prysznica takiego jak na Ziemi."},
{"Funfact: Wasser wird auf Raumstationen sehr sorgfaeltig wiederverwendet.","Funfact: Water is recycled very carefully on space stations.","Ciekawostka: Woda na stacjach kosmicznych jest bardzo starannie odzyskiwana."},
{"Funfact: Astronauten schlafen in Schlafsaecken, die an der Wand befestigt sind.","Funfact: Astronauts sleep in sleeping bags attached to a wall.","Ciekawostka: Astronauci spia w spiworach przymocowanych do sciany."},
{"Funfact: Ohne Erdschwere kann die Wirbelsaeule etwas laenger werden.","Funfact: Without Earth gravity the spine can stretch a little.","Ciekawostka: Bez ziemskiej grawitacji kregoslup moze sie troche wydluzyc."},
{"Funfact: Muskeltraining ist im All Pflicht, damit Muskeln und Knochen stark bleiben.","Funfact: Exercise is mandatory in space to keep muscles and bones strong.","Ciekawostka: Cwiczenia w kosmosie sa obowiazkowe dla miesni i kosci."},
{"Funfact: Die ISS wurde aus vielen Modulen im Orbit zusammengesetzt.","Funfact: The ISS was assembled from many modules in orbit.","Ciekawostka: ISS zostala zlozona z wielu modulow na orbicie."},
{"Funfact: Das Hubble-Teleskop wurde mehrfach im All repariert.","Funfact: The Hubble telescope was repaired in space several times.","Ciekawostka: Teleskop Hubble'a byl kilka razy naprawiany w kosmosie."},
{"Funfact: Voyager 1 ist das fernste menschengemachte Objekt.","Funfact: Voyager 1 is the farthest human-made object.","Ciekawostka: Voyager 1 jest najdalszym obiektem zbudowanym przez czlowieka."},
{"Funfact: Funksignale zum Mars brauchen je nach Abstand mehrere Minuten.","Funfact: Radio signals to Mars take several minutes depending on distance.","Ciekawostka: Sygnaly radiowe na Marsa leca kilka minut, zaleznie od odleglosci."},
{"Funfact: Auf dem Mond gibt es keine dichte Atmosphaere und keinen Wind wie auf der Erde.","Funfact: The Moon has no dense atmosphere and no Earth-like wind.","Ciekawostka: Ksiezyc nie ma gestej atmosfery ani ziemskiego wiatru."},
{"Funfact: Fussabdruecke auf dem Mond koennen sehr lange erhalten bleiben.","Funfact: Footprints on the Moon can remain for a very long time.","Ciekawostka: Slady stop na Ksiezycu moga przetrwac bardzo dlugo."},
{"Funfact: Raketen starten oft nach Osten, um die Erdrotation zu nutzen.","Funfact: Rockets often launch eastward to use Earth's rotation.","Ciekawostka: Rakiety czesto startuja na wschod, aby wykorzystac obrot Ziemi."},
{"Funfact: Der groesste Teil einer Rakete besteht beim Start aus Treibstoff.","Funfact: Most of a rocket at launch is fuel.","Ciekawostka: Wiekszosc rakiety przy starcie stanowi paliwo."},
{"Funfact: Ein Orbit ist ein staendiges Fallen um die Erde herum.","Funfact: An orbit is continuous falling around Earth.","Ciekawostka: Orbita to ciagle spadanie wokol Ziemi."},
{"Funfact: Schwerelosigkeit im Orbit entsteht, weil alles gemeinsam faellt.","Funfact: Weightlessness in orbit happens because everything falls together.","Ciekawostka: Niewazkosc na orbicie powstaje, bo wszystko spada razem."},
{"Funfact: Die Erde zeigt aus dem All eine duenne blaue Atmosphaerenschicht.","Funfact: From space Earth shows a thin blue atmospheric layer.","Ciekawostka: Z kosmosu atmosfera Ziemi wyglada jak cienka niebieska warstwa."},
{"Funfact: Polarlichter koennen von der ISS aus sehr gut beobachtet werden.","Funfact: Auroras can be observed very well from the ISS.","Ciekawostka: Zorze polarne widac z ISS bardzo dobrze."},
{"Funfact: Blitze in Gewittern sind aus dem Orbit deutlich sichtbar.","Funfact: Lightning in storms is clearly visible from orbit.","Ciekawostka: Blyskawice w burzach sa wyraznie widoczne z orbity."},
{"Funfact: Die ersten Satelliten waren viel kleiner als heutige Satelliten.","Funfact: The first satellites were much smaller than modern satellites.","Ciekawostka: Pierwsze satelity byly znacznie mniejsze niz dzisiejsze."},
{"Funfact: Sputnik 1 war 1957 der erste kuenstliche Satellit.","Funfact: Sputnik 1 was the first artificial satellite in 1957.","Ciekawostka: Sputnik 1 byl pierwszym sztucznym satelita w 1957 roku."},
{"Funfact: GPS funktioniert mit sehr genauen Atomuhren auf Satelliten.","Funfact: GPS works with very accurate atomic clocks on satellites.","Ciekawostka: GPS dziala dzieki bardzo dokladnym zegarom atomowym na satelitach."},
{"Funfact: Relativitaetseffekte muessen bei GPS korrigiert werden.","Funfact: Relativity effects must be corrected for GPS.","Ciekawostka: W GPS trzeba poprawiac efekty teorii wzglednosci."},
{"Funfact: Viele Erdbeobachtungssatelliten fliegen ueber die Pole.","Funfact: Many Earth observation satellites fly over the poles.","Ciekawostka: Wiele satelitow obserwacji Ziemi lata nad biegunami."},
{"Funfact: Ein geostationaerer Satellit bleibt scheinbar ueber demselben Ort.","Funfact: A geostationary satellite appears to stay above one place.","Ciekawostka: Satelita geostacjonarny pozornie pozostaje nad jednym miejscem."},
{"Funfact: Geostationaere Satelliten kreisen in rund 35786 km Hoehe.","Funfact: Geostationary satellites orbit at about 35786 km altitude.","Ciekawostka: Satelity geostacjonarne kraza na wysokosci okolo 35786 km."},
{"Funfact: Die ISS fliegt deutlich niedriger als geostationaere Satelliten.","Funfact: The ISS flies much lower than geostationary satellites.","Ciekawostka: ISS lata znacznie nizej niz satelity geostacjonarne."},
{"Funfact: Die ISS muss regelmaessig angehoben werden, weil sie langsam absinkt.","Funfact: The ISS must be boosted regularly because it slowly loses altitude.","Ciekawostka: ISS trzeba regularnie podnosic, bo powoli traci wysokosc."},
{"Funfact: Auch in ISS-Hoehe gibt es noch winzige Reste der Atmosphaere.","Funfact: Even at ISS altitude tiny traces of atmosphere remain.","Ciekawostka: Nawet na wysokosci ISS sa sladowe resztki atmosfery."},
{"Funfact: Kleine Triebwerkszuendungen koennen die Bahn der ISS korrigieren.","Funfact: Small thruster burns can correct the ISS orbit.","Ciekawostka: Krotkie odpalenia silnikow moga korygowac orbite ISS."},
{"Funfact: Beim Andocken muessen Geschwindigkeit und Position extrem genau passen.","Funfact: Docking requires extremely precise speed and position.","Ciekawostka: Dokowanie wymaga bardzo dokladnej predkosci i pozycji."},
{"Funfact: Die Sojus-Kapsel landet mit Fallschirmen und Bremsraketen.","Funfact: The Soyuz capsule lands with parachutes and braking rockets.","Ciekawostka: Kapsula Sojuz laduje ze spadochronami i rakietami hamujacymi."},
{"Funfact: Apollo-Kapseln landeten im Ozean und wurden von Schiffen geborgen.","Funfact: Apollo capsules landed in the ocean and were recovered by ships.","Ciekawostka: Kapsuly Apollo ladowaly w oceanie i byly odbierane przez statki."},
{"Funfact: Space-Shuttle-Orbiter landeten wie Gleitflugzeuge ohne Motorleistung.","Funfact: Space Shuttle orbiters landed like gliders without engine power.","Ciekawostka: Wahadlowce ladowaly jak szybowce bez pracy silnikow."},
{"Funfact: Der Mars hat den groessten Vulkan des Sonnensystems: Olympus Mons.","Funfact: Mars has the largest volcano in the Solar System: Olympus Mons.","Ciekawostka: Mars ma najwiekszy wulkan Ukladu Slonecznego: Olympus Mons."},
{"Funfact: Der Mars-Tag ist nur etwa 40 Minuten laenger als ein Erdtag.","Funfact: A Mars day is only about 40 minutes longer than an Earth day.","Ciekawostka: Doba marsjanska jest tylko okolo 40 minut dluzsza od ziemskiej."},
{"Funfact: Der Mond entfernt sich jedes Jahr ein kleines Stueck von der Erde.","Funfact: The Moon moves a small distance farther from Earth each year.","Ciekawostka: Ksiezyc co roku oddala sie troche od Ziemi."},
{"Funfact: Die Venus rotiert sehr langsam und in entgegengesetzter Richtung.","Funfact: Venus rotates very slowly and in the opposite direction.","Ciekawostka: Wenus obraca sie bardzo wolno i w przeciwnym kierunku."},
{"Funfact: Ein Tag auf der Venus ist laenger als ein Venusjahr.","Funfact: A day on Venus is longer than a Venus year.","Ciekawostka: Dzien na Wenus jest dluzszy niz rok wenusjanski."},
{"Funfact: Merkur hat trotz Sonnennaehe extrem kalte Schattenbereiche an den Polen.","Funfact: Mercury has extremely cold polar shadows despite being near the Sun.","Ciekawostka: Merkury ma bardzo zimne cienie przy biegunach mimo bliskosci Slonca."},
{"Funfact: Jupiter ist der groesste Planet unseres Sonnensystems.","Funfact: Jupiter is the largest planet in our Solar System.","Ciekawostka: Jowisz jest najwieksza planeta Ukladu Slonecznego."},
{"Funfact: Der Grosse Rote Fleck auf Jupiter ist ein riesiger Sturm.","Funfact: Jupiter's Great Red Spot is a huge storm.","Ciekawostka: Wielka Czerwona Plama na Jowiszu to ogromna burza."},
{"Funfact: Saturns Ringe bestehen aus Eis- und Gesteinsbrocken.","Funfact: Saturn's rings are made of ice and rock fragments.","Ciekawostka: Pierscienie Saturna skladaja sie z lodu i skal."},
{"Funfact: Uranus ist stark gekippt und rollt gewissermassen um die Sonne.","Funfact: Uranus is strongly tilted and almost rolls around the Sun.","Ciekawostka: Uran jest mocno przechylony i jakby toczy sie wokol Slonca."},
{"Funfact: Neptun hat sehr schnelle Winde in seiner Atmosphaere.","Funfact: Neptune has very fast winds in its atmosphere.","Ciekawostka: Neptun ma bardzo szybkie wiatry w atmosferze."},
{"Funfact: Pluto wurde 2006 als Zwergplanet neu eingeordnet.","Funfact: Pluto was reclassified as a dwarf planet in 2006.","Ciekawostka: Pluton w 2006 roku zostal uznany za planete karlowata."},
{"Funfact: Kometen bestehen aus Eis, Staub und Gestein.","Funfact: Comets are made of ice, dust, and rock.","Ciekawostka: Komety skladaja sie z lodu, pylu i skal."},
{"Funfact: Ein Kometenschweif zeigt meist von der Sonne weg.","Funfact: A comet tail usually points away from the Sun.","Ciekawostka: Warkocz komety zwykle wskazuje od Slonca."},
{"Funfact: Asteroiden sind Reste aus der Entstehungszeit des Sonnensystems.","Funfact: Asteroids are leftovers from the formation of the Solar System.","Ciekawostka: Asteroidy sa pozostalosciami z czasow powstawania Ukladu Slonecznego."},
{"Funfact: Meteoriten sind Weltraumgestein, das den Erdboden erreicht.","Funfact: Meteorites are space rocks that reach the ground.","Ciekawostka: Meteoryty to kosmiczne skaly, ktore docieraja do ziemi."},
{"Funfact: Sternschnuppen sind meist kleine Teilchen, die in der Atmosphaere vergluehen.","Funfact: Shooting stars are usually tiny particles burning in the atmosphere.","Ciekawostka: Spadajace gwiazdy to zwykle male czastki spalajace sie w atmosferze."},
{"Funfact: Die Milchstrasse enthaelt hunderte Milliarden Sterne.","Funfact: The Milky Way contains hundreds of billions of stars.","Ciekawostka: Droga Mleczna zawiera setki miliardow gwiazd."},
{"Funfact: Unsere Sonne ist ein Stern mittlerer Groesse.","Funfact: Our Sun is a medium-sized star.","Ciekawostka: Nasze Slonce jest gwiazda sredniej wielkosci."},
{"Funfact: Licht von der Sonne braucht etwa acht Minuten bis zur Erde.","Funfact: Sunlight takes about eight minutes to reach Earth.","Ciekawostka: Swiatlo Slonca dociera do Ziemi w okolo osiem minut."},
{"Funfact: Licht vom Mond braucht nur etwas mehr als eine Sekunde zur Erde.","Funfact: Moonlight takes just over one second to reach Earth.","Ciekawostka: Swiatlo z Ksiezyca dociera do Ziemi w nieco ponad sekunde."},
{"Funfact: Radiowellen reisen im Vakuum mit Lichtgeschwindigkeit.","Funfact: Radio waves travel through vacuum at the speed of light.","Ciekawostka: Fale radiowe w prozni poruszaja sie z predkoscia swiatla."},
{"Funfact: Raumsonden nutzen oft Swing-by-Manoever, um Geschwindigkeit zu gewinnen.","Funfact: Space probes often use gravity assists to gain speed.","Ciekawostka: Sondy kosmiczne czesto uzywaja asysty grawitacyjnej."},
{"Funfact: Bei einem Swing-by gibt ein Planet winzige Bahnenergie an eine Sonde ab.","Funfact: During a gravity assist a planet gives a probe tiny orbital energy.","Ciekawostka: Przy asyscie grawitacyjnej planeta przekazuje sondzie odrobine energii."},
{"Funfact: Die Cassini-Sonde erforschte viele Jahre lang Saturn und seine Monde.","Funfact: Cassini explored Saturn and its moons for many years.","Ciekawostka: Cassini przez wiele lat badala Saturna i jego ksiezyce."},
{"Funfact: Die Galileo-Sonde untersuchte Jupiter und seine Monde.","Funfact: Galileo studied Jupiter and its moons.","Ciekawostka: Galileo badala Jowisza i jego ksiezyce."},
{"Funfact: Die New-Horizons-Sonde flog 2015 an Pluto vorbei.","Funfact: New Horizons flew past Pluto in 2015.","Ciekawostka: New Horizons przeleciala obok Plutona w 2015 roku."},
{"Funfact: Der Marsrover Curiosity landete mit einem Skycrane-System.","Funfact: The Curiosity Mars rover landed using a sky crane system.","Ciekawostka: Lazik Curiosity ladowal na Marsie z systemem sky crane."},
{"Funfact: Marsrover fahren langsam, weil Sicherheit wichtiger ist als Tempo.","Funfact: Mars rovers drive slowly because safety matters more than speed.","Ciekawostka: Laziki marsjanskie jada wolno, bo bezpieczenstwo jest wazniejsze."},
{"Funfact: Solarpanels liefern vielen Raumsonden elektrische Energie.","Funfact: Solar panels provide electrical power for many space probes.","Ciekawostka: Panele sloneczne zasilaja wiele sond kosmicznych."},
{"Funfact: Weit draussen im Sonnensystem werden oft Radioisotopengeneratoren genutzt.","Funfact: Far out in the Solar System probes often use radioisotope generators.","Ciekawostka: Daleko w Ukladzie Slonecznym sondy czesto uzywaja generatorow radioizotopowych."},
{"Funfact: Raumfahrzeuge muessen extreme Temperaturunterschiede aushalten.","Funfact: Spacecraft must withstand extreme temperature differences.","Ciekawostka: Statki kosmiczne musza znosic skrajne roznice temperatur."},
{"Funfact: Im Vakuum gibt es keine Luft, die Waerme durch Konvektion abtransportiert.","Funfact: In vacuum there is no air to remove heat by convection.","Ciekawostka: W prozni nie ma powietrza, ktore odbiera cieplo konwekcja."},
{"Funfact: Normale Bleistiftteilchen waeren in Schwerelosigkeit problematisch.","Funfact: Ordinary pencil particles would be troublesome in weightlessness.","Ciekawostka: Zwykle czastki olowka bylyby klopotliwe w niewazkosci."},
{"Funfact: Spezielle Stifte funktionieren in vielen Lagen und auch in Schwerelosigkeit.","Funfact: Special pens work in many orientations and in weightlessness.","Ciekawostka: Specjalne dlugopisy dzialaja w wielu polozeniach i w niewazkosci."},
{"Funfact: Essen im All wird oft so verpackt, dass keine Kruemel frei schweben.","Funfact: Food in space is packaged to keep crumbs from floating away.","Ciekawostka: Jedzenie w kosmosie pakuje sie tak, aby okruchy nie lataly."},
{"Funfact: Brot wird im All oft durch Tortillas ersetzt, weil sie weniger kruemeln.","Funfact: Bread is often replaced by tortillas in space because they crumble less.","Ciekawostka: Chleb w kosmosie czesto zastepuja tortille, bo mniej sie krusza."},
{"Funfact: Fluessigkeiten bilden in Schwerelosigkeit kugelige Tropfen.","Funfact: Liquids form round droplets in weightlessness.","Ciekawostka: Plyny w niewazkosci tworza kuliste krople."},
{"Funfact: Feuer verhaelt sich in Schwerelosigkeit anders als auf der Erde.","Funfact: Fire behaves differently in weightlessness than on Earth.","Ciekawostka: Ogien w niewazkosci zachowuje sie inaczej niz na Ziemi."},
{"Funfact: Flammen koennen in Schwerelosigkeit eher kugelfoermig aussehen.","Funfact: Flames can look more spherical in weightlessness.","Ciekawostka: Plomienie w niewazkosci moga wygladac bardziej kuliscie."},
{"Funfact: Astronauten trainieren Aussenbordeinsaetze oft unter Wasser.","Funfact: Astronauts often train for spacewalks underwater.","Ciekawostka: Astronauci czesto trenuja spacery kosmiczne pod woda."},
{"Funfact: Der Neutral Buoyancy Pool der NASA ist ein riesiges Trainingsbecken.","Funfact: NASA's Neutral Buoyancy Pool is a huge training pool.","Ciekawostka: Basen Neutral Buoyancy NASA to ogromny basen treningowy."},
{"Funfact: Bei einem Weltraumspaziergang bleibt ein Astronaut durch Leinen gesichert.","Funfact: During a spacewalk an astronaut stays secured by tethers.","Ciekawostka: Podczas spaceru kosmicznego astronauta jest zabezpieczony linami."},
{"Funfact: Raumanzug-Handschuhe sind technisch besonders anspruchsvoll.","Funfact: Spacesuit gloves are especially difficult engineering.","Ciekawostka: Rekawice skafandra sa szczegolnie trudne technicznie."},
{"Funfact: Die ISS nutzt grosse Radiatoren, um Waerme ins All abzugeben.","Funfact: The ISS uses large radiators to reject heat into space.","Ciekawostka: ISS uzywa duzych radiatorow, aby oddawac cieplo w kosmos."},
{"Funfact: Im All kann Waerme nur durch Strahlung wirklich abgegeben werden.","Funfact: In space heat can really be removed only by radiation.","Ciekawostka: W kosmosie cieplo mozna naprawde oddawac tylko przez promieniowanie."},
{"Funfact: Satelliten muessen vor geladenen Teilchen der Sonne geschuetzt werden.","Funfact: Satellites must be protected from charged particles from the Sun.","Ciekawostka: Satelity trzeba chronic przed naladowanymi czastkami ze Slonca."},
{"Funfact: Sonnenstuerme koennen Funkverbindungen und Satelliten stoeren.","Funfact: Solar storms can disturb radio links and satellites.","Ciekawostka: Burze sloneczne moga zaklocac lacznosc radiowa i satelity."},
{"Funfact: Der Van-Allen-Guertel enthaelt energiereiche geladene Teilchen.","Funfact: The Van Allen belts contain energetic charged particles.","Ciekawostka: Pasy Van Allena zawieraja energetyczne naladowane czastki."},
{"Funfact: Raumfahrzeuge muessen Mikrometeoriten und Weltraumschrott beachten.","Funfact: Spacecraft must consider micrometeorites and space debris.","Ciekawostka: Statki kosmiczne musza uwzgledniac mikrometeoryty i smieci kosmiczne."},
{"Funfact: Weltraumschrott wird verfolgt, damit Satelliten ausweichen koennen.","Funfact: Space debris is tracked so satellites can dodge it.","Ciekawostka: Smieci kosmiczne sa sledzone, aby satelity mogly ich unikac."},
{"Funfact: Die ISS kann bei Bedarf Ausweichmanoever gegen Weltraumschrott fliegen.","Funfact: The ISS can perform avoidance maneuvers against space debris.","Ciekawostka: ISS moze wykonac manewr uniku przed smieciami kosmicznymi."},
{"Funfact: Viele Satelliten vergluehen am Ende ihrer Mission in der Atmosphaere.","Funfact: Many satellites burn up in the atmosphere at mission end.","Ciekawostka: Wiele satelitow spala sie w atmosferze po koncu misji."},
{"Funfact: Manche Raumsonden werden absichtlich auf Planeten oder Monde gelenkt.","Funfact: Some probes are deliberately guided into planets or moons.","Ciekawostka: Niektore sondy celowo kieruje sie na planety lub ksiezyce."},
{"Funfact: Planetenschutz soll verhindern, dass irdische Mikroben andere Welten verunreinigen.","Funfact: Planetary protection helps keep Earth microbes off other worlds.","Ciekawostka: Ochrona planetarna ogranicza przenoszenie ziemskich mikrobow."},
{"Funfact: Europa, ein Mond des Jupiter, besitzt wahrscheinlich einen Ozean unter Eis.","Funfact: Europa, a moon of Jupiter, probably has an ocean under ice.","Ciekawostka: Europa, ksiezyc Jowisza, prawdopodobnie ma ocean pod lodem."},
{"Funfact: Enceladus, ein Saturnmond, schleudert Eisfontaenen ins All.","Funfact: Enceladus, a moon of Saturn, sprays icy plumes into space.","Ciekawostka: Enceladus, ksiezyc Saturna, wyrzuca lodowe piuropusze w kosmos."},
{"Funfact: Titan hat eine dichte Atmosphaere und Seen aus Kohlenwasserstoffen.","Funfact: Titan has a dense atmosphere and lakes of hydrocarbons.","Ciekawostka: Titan ma gesta atmosfere i jeziora weglowodorow."},
{"Funfact: Der erste deutsche ESA-Astronaut war Ulf Merbold.","Funfact: The first German ESA astronaut was Ulf Merbold.","Ciekawostka: Pierwszym niemieckim astronauta ESA byl Ulf Merbold."},
{"Funfact: Alexander Gerst verbrachte mehrere Missionen auf der ISS.","Funfact: Alexander Gerst spent several missions on the ISS.","Ciekawostka: Alexander Gerst spedzil kilka misji na ISS."},
{"Funfact: Auf der ISS arbeiten meist mehrere Nationen gleichzeitig zusammen.","Funfact: Several nations usually work together on the ISS.","Ciekawostka: Na ISS zwykle wspolpracuje kilka narodow."},
{"Funfact: Raumfahrtmissionen werden oft viele Jahre vor dem Start geplant.","Funfact: Space missions are often planned many years before launch.","Ciekawostka: Misje kosmiczne planuje sie czesto wiele lat przed startem."},
{"Funfact: Ein Startfenster ist der Zeitraum, in dem ein Start besonders guenstig ist.","Funfact: A launch window is the time when a launch is especially favorable.","Ciekawostka: Okno startowe to czas, gdy start jest szczegolnie korzystny."},
};
const char *funfact_get(UWORD index, UBYTE language){ const FunfactText *f; if(index>=funfact_count()) index=0; f=&facts[index]; if(language==ISS_LANG_EN) return f->en; if(language==ISS_LANG_PL) return f->pl; return f->de; }
UWORD funfact_count(void){ return (UWORD)(sizeof(facts)/sizeof(facts[0])); }
